  ('social-worker-moex-02936', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會保險與私人保險的特性比較，下列何者錯誤？', '["社會保險是強制性的，私人保險是自願性的", "社會保險的成本難以預測，私人保險則比較容易事先精算", "社會保險具有水平風險分擔效果，私人保險偏向垂直風險分擔效果", "社會保險財源來自被保險人、雇主與政府，私人保險財源主要來自被保險人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02937', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國老人福利法第28條中指出「主管機關應協調各目的事業主管機關鼓勵老人參與志願服務。」而1991 年聯合國老人綱領中也提倡老年人的志願服務。因此，推動老人的志願服務，是要追求聯合國老人綱領 中的那一項目標？', '["獨立", "參與", "照顧", "尊嚴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02938', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列那一項敘述不符合我國老人福利法中對老人福利機構之規定？', '["老人福利機構可分為：長期照顧機構、安養機構及其他老人福利機構", "公設民營機構名稱不冠以公立或私立", "私人或團體設立老人福利機構，應向中央主管機關申請設立許可", "老人福利機構不得兼營營利行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02939', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '現行兒童及少年福利與權益保障法新增那一個目的事業主管機關應設置社會工作人員或輔導人員？', '["通訊傳播主管機關", "文化主管機關", "法務主管機關", "教育主管機關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02940', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '相較於兒童及少年福利法，新修訂之兒童及少年福利與權益保障法不包括下列那一特色？', '["從保護觀點邁向解放觀點，強化兒少的公民權與社會權", "新增村里幹事為責任通報人", "規定犯有性騷擾罪者，不得擔任兒少機構的負責人或工作人員", "強化收出養媒合的必要作為，明訂以國外收養為優先"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02941', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '當兒童或少年未獲適當之養育或照顧，主管機關應予緊急保護、安置或為其他必要之處置。此一緊急安 置不得超過：', '["24小時", "48小時", "72小時", "沒有限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02942', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '負責身心障礙者之財產信託的規劃、推動及監督等工作是那一個目的事業主管機關？', '["內政部", "財政主管機關", "金融主管機關", "經濟主管機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02943', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國身心障礙者權益保障法規定，身心障礙證明有效期限最長為幾年？', '["四年", "五年", "六年", "七年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02944', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國社會救助法規定，下列那一類人員在執行業務知悉有社會救助需要之個人或家庭時，沒有強制通報 直轄市、縣（市）主管機關之要求？', '["警察人員", "村（里）長", "醫事人員", "村（里）幹事"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02945', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '直轄市、縣（市）主管機關為協助低收入戶積極自立，得自行或運用民間資源辦理脫離貧窮相關措施。 參與這些措施之低收入戶，於一定期間及額度內因措施所增加之收入及存款，得免計入社會救助法第 4 條第1項之家庭總收入及家庭財產。免計入之期限最長為幾年？', '["以一年為限", "以二年為限", "以三年為限", "以五年為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02946', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '直轄市、縣（市）主管機關應就兒童及少年保護個案進行家庭處遇。有關家庭處遇計畫之敘述，何者錯誤？', '["兒少家庭處遇計畫應於三個月內提出執行", "家庭處遇計畫應包括家庭功能、兒童少年安置與安全評估、家庭福利服務等", "家庭處遇計畫在實務上又稱為高風險家庭關懷輔導", "家庭處遇計畫要求兒少照顧者應配合參與親職教育、戒癮治療、精神治療等功能性協助"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02947', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何者不屬於中華民國人口政策綱領政策內涵中的內容？', '["強化原住民族及其他弱勢者就業能力，創造就業機會，改善生活環境", "建立區域合作機制，以提高各生活圈居民之機會與生活品質", "健全收養、出養制度及非婚生育支援體系", "充實社工人力，培訓分科分級之家庭教育人才養成"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02948', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '性別主流化是當前國際社會推動性別平等的主要策略，以下敘述何者錯誤？', '["性別主流化關注對政策發展、研究、倡導/對話、評估、資源配置的過程", "性別主流化的六大工具中，以性別統計和性別分析為重要的基礎工程", "性別影響評估會決定後續的政策資源配置，因此在性別目標擬訂上，應力求形式平等", "性別平等機制的主要功能是改造與導入性別意識於組織實際運作層次，以促發創新與彈性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02949', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '為協助平衡工作與家庭，減少父母親職負擔，目前法律上訂有多項促進工作平等措施。下列何者不包括 在內？', '["受僱者於其配偶分娩時，雇主應給予三日的有薪陪產假", "受僱者任職滿一年後，於每一子女滿三歲前，得申請育嬰留職停薪至多二年", "前述育嬰留職停薪期間，可選擇繼續參加原有社會保險，保險費可遞延三年繳納", "育嬰留職停薪期間，父母雙方可合併申請原投保薪資六成之育嬰津貼，為期各十二個月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02950', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列那一項保險提供現金的生育給付？', '["勞工保險", "公教人員保險", "軍人保險", "全民健康保險"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02951', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國社會救助法規定，家中若有三類型低收入戶成員，主管機關得依其原領取現金給付之金額增加百分 之二十至四十之補助，下列何者不在其列？', '["年滿65歲以上者", "懷孕滿3個月", "領有身心障礙手冊或證明", "未滿12歲之兒童"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02952', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國社會救助法新制於民國100年實施，有幾項重要的突破，下列何者正確？', '["所有職場弱勢者核算工作收入皆為基本工資之70%", "中低收入戶係全家總收入平均分配全家人口，每人每月不超過最低生活費二倍", "最低生活費以每年消費支出60%訂定之", "懷胎期間經醫生診斷不宜工作者，認定為無工作能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02953', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '在討論致貧原因時，通常有個人歸因與結構歸因兩大觀點。下列敘述中那一項是屬於結構性歸因的說法？', '["新移民無法享有政治上的地位，因此影響其就業機會而造成貧窮", "政府應讓窮人負起相對義務，強制接受福利的窮人去工作", "不強迫窮人接受工作會造成福利依賴", "窮人為了領政府的補助而生更多小孩"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02954', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關家庭暴力防治法中民事保護令的敘述，下列何者錯誤？', '["可分為通常保護令、暫時保護令、緊急保護令三種", "保護令聲請除由被害人或其法定代理人為之外，也可由警察與社工代為聲請", "通常保護令之有效期限為一年以下，失效前可聲請延長，但以一次為限", "保護令之審理應從嚴從速，且審理不得公開，但可以申請進行調解或和解"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
